const username = query.trim().toLowerCase();
if (!username) return 'ERROR: username required';
const r = await $http({
  method: 'POST',
  url: 'http://helpdesk-ldap-api:5000/lookup',
  headers: {'Content-Type': 'application/json'},
  body: JSON.stringify({username})
});
const d = typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
if (!d.found) return 'User not found: ' + username;
return 'User: ' + d.displayName + ' (' + username + ')'
  + ' | Dept: ' + d.department
  + ' | Title: ' + d.title
  + ' | Email: ' + d.email
  + ' | Status: ' + d.status
  + ' | DN: ' + d.dn;

const username = query.trim().toLowerCase();
if (!username) return 'ERROR: username required';
const r = await $http({
  method: 'POST',
  url: 'http://helpdesk-ldap-api:5000/unlock',
  headers: {'Content-Type': 'application/json'},
  body: JSON.stringify({username})
});
const d = typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
if (d.success) return 'SUCCESS: ' + d.message;
return 'ERROR: ' + (d.error || 'Unknown error');

const username = query.trim().toLowerCase();
if (!username) return 'ERROR: username required';
const r = await $http({
  method: 'POST',
  url: 'http://helpdesk-ldap-api:5000/reset-password',
  headers: {'Content-Type': 'application/json'},
  body: JSON.stringify({username})
});
const d = typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
if (d.success) return 'SUCCESS: Password reset for ' + username + '. Temporary password: ' + d.tempPassword;
return 'ERROR: ' + (d.error || 'Unknown error');

const keywords = query.trim().toLowerCase();
if (!keywords) return 'ERROR: keywords required';
const r = await $http({
  method: 'GET',
  url: 'http://helpdesk-ldap-api:5000/search-kb?q=' + encodeURIComponent(keywords)
});
const d = typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
if (!d.results || d.results.length === 0) return 'No KB article found for: ' + keywords + '. Consider escalating to N2.';
return d.results.map(a => 'ARTICLE: ' + a.title + '\n' + a.solution_text).join('\n\n');

let data;
try { data = JSON.parse(query); }
catch(e) { data = {action_type: 'agent_action', target_user: 'unknown', details: query}; }
const r = await $http({
  method: 'POST',
  url: 'http://helpdesk-ldap-api:5000/log-action',
  headers: {'Content-Type': 'application/json'},
  body: JSON.stringify(data)
});
const d = typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
return 'Logged: ID ' + (d.id || 'ok');
